import pandas as pdfrom indicators import (    calculate_moving_average,    calculate_daily_return,    calculate_volatility,    calculate_highest_price,    calculate_lowest_price,    calculate_max_drawdown,    calculate_market_indicators,)def sample_market_data():    return pd.DataFrame(        {            "Open": [100, 105, 110, 108, 115],            "High": [106, 112, 113, 118, 120],            "Low": [99, 104, 107, 106, 114],            "Close": [105, 110, 108, 115, 118],            "Volume": [0, 0, 0, 0, 0],        }    )def test_calculate_moving_average():    df = sample_market_data()    moving_average = calculate_moving_average(df, window=3)    assert round(moving_average.iloc[-1], 2) == 113.67def test_calculate_daily_return():    df = sample_market_data()    daily_return = calculate_daily_return(df)    assert round(daily_return, 2) == 2.61def test_calculate_volatility():    df = sample_market_data()    volatility = calculate_volatility(df)    assert volatility is not None    assert volatility > 0def test_calculate_highest_price():    df = sample_market_data()    highest_price = calculate_highest_price(df)    assert highest_price == 120def test_calculate_lowest_price():    df = sample_market_data()    lowest_price = calculate_lowest_price(df)    assert lowest_price == 99def test_calculate_max_drawdown():    df = sample_market_data()    max_drawdown = calculate_max_drawdown(df)    assert max_drawdown < 0def test_calculate_market_indicators_returns_expected_keys():    df = sample_market_data()    indicators = calculate_market_indicators(df)    expected_keys = {        "latest_close",        "moving_average",        "daily_return",        "volatility",        "highest_price",        "lowest_price",        "max_drawdown",    }    assert set(indicators.keys()) == expected_keysdef test_calculate_market_indicators_handles_empty_dataframe():    df = pd.DataFrame()    indicators = calculate_market_indicators(df)    assert indicators["latest_close"] is None    assert indicators["moving_average"] is None    assert indicators["daily_return"] is None    assert indicators["volatility"] is None    assert indicators["highest_price"] is None    assert indicators["lowest_price"] is None    assert indicators["max_drawdown"] is None